const data = $input.first().json;
if (!data.notificacoes || data.notificacoes.length === 0) return [];
return data.notificacoes.map(n => ({ json: n }));

const n = $input.first().json;
const payload = n.payload || {};
const tipo = n.tipo;
const phone = '55' + String(n.celular).replace(/\D/g, '') + '@s.whatsapp.net';
const apelido = n.apelido || 'você';

function brl(v) {
  const parts = parseFloat(v).toFixed(2).split('.');
  parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return 'R$ ' + parts[0] + ',' + parts[1];
}

function num(v) {
  const parts = parseFloat(v).toFixed(2).split('.');
  parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return parts[0] + ',' + parts[1];
}

function num8(v) {
  const parts = parseFloat(v).toFixed(8).split('.');
  parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return parts[0] + ',' + parts[1];
}

function fmtDate(d) {
  try { return new Date(d).toLocaleDateString('pt-BR'); } catch(e) { return d; }
}

let mensagem = '';
if (tipo === 'deposito_confirmado') {
  mensagem = '🥳 Boa notícia, ' + apelido + '!

Recebemos seu depósito de ' + brl(payload.valor) + '.

Já estamos trabalhando para atingir nossas metas! 🎯

Se quiser conferir todos os detalhes, acesse a sua conta:

www.purg.com.br';
} else if (tipo === 'saque_confirmado') {
  mensagem = '💰 Dinheiro a caminho, ' + apelido + '!

Seu pedido de saque de ' + brl(payload.valor) + ' foi processado.

Em até 1 dia útil o valor estará disponível na sua conta cadastrada.

Confira os detalhes da transação na sua conta:

www.purg.com.br';
} else if (tipo === 'saque_falhou') {
  mensagem = '⚠️ Ops, ' + apelido + '! Tivemos um problema.

Não conseguimos concluir seu saque de ' + brl(payload.valor) + '.

Motivo: ' + (payload.motivo || 'erro interno') + '

Mas não se preocupe! Você pode ajustar isso e tentar novamente na sua conta:

www.purg.com.br';
} else if (tipo === 'meta_atingida') {
  mensagem = '🎯 Meta batida, ' + apelido + '!

Estamos mandando muito bem no nosso objetivo de ' + payload.objetivo_nome + '!!

💰 Resumo do Objetivo

Objetivo: ' + brl(payload.objetivo_valor_total) + '
Total Investido: ' + brl(payload.investido) + '
Percentual Atingido: ' + payload.percentual_atingido + '%
Metas Concluídas: ' + payload.metas_concluidas + '/' + payload.metas_totais + '

Vamos juntos continuar evoluindo seu patrimônio para alcançarmos novos objetivos.

Se quiser mais detalhes, acesse a sua conta:

www.purg.com.br';
} else if (tipo === 'meta_mensal_incompleta') {
  const meses = ['janeiro','fevereiro','março','abril','maio','junho','julho','agosto','setembro','outubro','novembro','dezembro'];
  const metas = payload.metas || [];
  const nomeMes = metas.length > 0 ? meses[new Date(metas[0].data_limite).getMonth()] : '';
  const titulo = metas.length === 1 ? '*Nossa meta mensal:*' : '*Nossas metas mensais:*';
  const linhas = metas.map(function(m) {
    const limite = new Date(m.data_limite).toLocaleDateString('pt-BR');
    return '💰 Esse mês depositamos ' + brl(m.valor_alocado) + ' (' + m.percentual + '% da meta)
🎯 A nossa meta esse mês é de ' + brl(m.valor_meta) + '
🗓️ Precisamos depositar até ' + limite;
  });
  mensagem = '🎯 ' + apelido + ', falta pouco para atingirmos as nossas metas de ' + nomeMes + '!

' + titulo + '
' + linhas.join('

') + '

Não deixe nada nos atrapalhar a alcançar o nosso objetivo!

Que tal fazer o nosso aporte agora na sua conta?

www.purg.com.br';
} else if (tipo === 'resumo_semanal') {
  mensagem = '*📊 Resumo da Semana*

' +
    'Olá, ' + apelido + '! Confira o desempenho da nossa jornada financeira nos últimos 7 dias:

' +
    'Objetivo: ' + brl(payload.objetivo_valor_total) + '
' +
    'Patrimônio: ' + brl(payload.saldo_alocado_total) + '
' +
    'Patrimônio x Objetivo (%): ' + payload.objetivo_percentual_alcancado + '%

' +
    '*📈 Performance da Semana*

' +
    'Rendimento: R$ ' + num(payload.rendimento_semana) + '
' +
    'Rendimento (%): ' + payload.rendimento_percentual + '%
' +
    'Depósitos: R$ ' + num(payload.depositos_semana) + '
' +
    'Saques: R$ ' + num(payload.saques_semana) + '

' +
    '*💰 Seu Patrimônio*

' +
    'Total Investido: R$ ' + num(payload.investido) + '
' +
    'Saldo Disponível: R$ ' + num8(payload.saldo) + '
' +
    'Rendimento Total Acumulado: R$ ' + num(payload.rendimento_total) + '

' +
    '*🏆 Rankings e Conquistas*

' +
    'Liga Atual: ' + payload.liga + '
' +
    'Posição no Ranking Global: #' + payload.posicao_ranking + '
' +
    'Pontuação Total: ' + payload.pontos_total + ' pontos

' +
    '*🎯 Rumo ao Objetivo*
' +
    'Meta mensal: ' + brl(payload.proxima_meta_bruta_financeiro) + '
' +
    'Nós já concluímos ' + payload.proxima_meta_percentual + '% dessa meta!

' +
    '*🗓️ Prazo final*
' +
    'Temos até o dia ' + fmtDate(payload.proxima_meta_data) + ' para finalizarmos essa meta.

' +
    'Que tal fazer um novo depósito para atingirmos o nosso objetivo mais rápido?

' +
    'Acesse o painel completo na sua conta:

www.purg.com.br';
} else if (tipo === 'novo_objetivo') {
  const parcelas = (payload.metas || []).map(function(v, i) {
    return 'Parcela ' + (i + 1) + ': ' + brl(v);
  }).join('
');
  mensagem = '🎉 ' + apelido + ', seja bem-vindo(a)!

' +
    'Eu sou a Purg e estou aqui para te acompanhar em cada passo dessa jornada rumo ao seu objetivo. Vamos juntos chegar lá!

' +
    '🎯 Seu Objetivo

' +
    'Objetivo: ' + brl(payload.objetivo_valor_total) + '
' +
    'Prazo final: ' + fmtDate(payload.data_limite) + '
' +
    'Aporte inicial: ' + brl(payload.aporte) + '

' +
    '📅 Plano de Metas Mensais

' +
    parcelas + '

' +
    'Não se preocupe que não vou te deixar largado, estarei sempre junto acompanhando e te lembrando.

' +
    'Se quiser ver mais ferramentas, acesse o nosso app:
www.purg.com.br';
}
return [{ json: { id: n.id, phone, mensagem } }];

